export function getSitePage(slug) {
  if (!slug) {
    return null;
  }

  return sitePages[slug] ?? null;
}

export function getSiteRouteSlugs() {
  return Object.keys(sitePages)
    .filter((slug) => slug !== "index")
    .sort();
}

